import{_ as t,o as a,c as i,ae as o}from"./chunks/framework.BuvKvcPh.js";const r="/Furniture-Designer/images/assembly-en.png",m=JSON.parse('{"title":"Assembly & Digital Tools","description":"","frontmatter":{},"headers":[],"relativePath":"assembly.md","filePath":"assembly.md"}'),l={name:"assembly.md"};function s(n,e,d,h,c,u){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="assembly-digital-tools" tabindex="-1">Assembly &amp; Digital Tools <a class="header-anchor" href="#assembly-digital-tools" aria-label="Permalink to &quot;Assembly &amp; Digital Tools&quot;">​</a></h1><p>A furniture piece requires robust joinery. This software embraces blind wooden dowel joinery (tourillons) by mathematically pinpointing where intersecting boards meet.</p><p><img src="'+r+'" alt="Assembly Tools Interface"></p><h2 id="dowel-hole-placement" tabindex="-1">Dowel Hole Placement <a class="header-anchor" href="#dowel-hole-placement" aria-label="Permalink to &quot;Dowel Hole Placement&quot;">​</a></h2><p>Dowel positions are calculated automatically when two boards intersect (e.g., a horizontal shelf meeting a vertical upright pane).</p><p>You can globally define:</p><ul><li><strong>Dowel Diameter</strong>: Generally 8mm standard.</li><li><strong>Dowel Length</strong>: The total physical length of the dowel. The software correctly calculates insertion depths for both the edge bore and face bore.</li><li><strong>Edge Margin</strong>: The minimum safety distance from the outer corner to the first hole.</li><li><strong>Spacing</strong>: The optimal gap between consecutive holes along a long join.</li></ul><h2 id="_3d-printable-assembly-jigs" tabindex="-1">3D Printable Assembly Jigs <a class="header-anchor" href="#_3d-printable-assembly-jigs" aria-label="Permalink to &quot;3D Printable Assembly Jigs&quot;">​</a></h2><p>Achieving perfectly perpendicular alignment manually is famously difficult. The software eliminates measuring errors by procedurally generating <strong>3D Printable Jigs</strong> customized to your exact material thickness.</p><h3 id="_1-the-edge-guide-guide-de-chant" tabindex="-1">1. The Edge Guide (Guide de Chant) <a class="header-anchor" href="#_1-the-edge-guide-guide-de-chant" aria-label="Permalink to &quot;1. The Edge Guide (Guide de Chant)&quot;">​</a></h3><p>A U-channel block designed to rest over the edge of a board. It features a pilot hole perfectly centered to guarantee your drill bit enters the end-grain straight.</p><h3 id="_2-the-face-guide-guide-equerre" tabindex="-1">2. The Face Guide (Guide Équerre) <a class="header-anchor" href="#_2-the-face-guide-guide-equerre" aria-label="Permalink to &quot;2. The Face Guide (Guide Équerre)&quot;">​</a></h3><p>An L-shaped right-angle piece designed to hook onto the face of the board. The pilot hole is offset precisely so the dowels perfectly mate with the edge-drilled board without misalignment.</p><h3 id="file-exports" tabindex="-1">File Exports <a class="header-anchor" href="#file-exports" aria-label="Permalink to &quot;File Exports&quot;">​</a></h3><ul><li><strong>STL</strong>: Download these jigs and slice them in Cura or PrusaSlicer. They print without supports in around 45 minutes.</li><li><strong>DXF</strong>: For users operating CNC routers, you can dump the entire flat-cut geometry as layered 2D DXF profiles.</li></ul>',15)])])}const p=t(l,[["render",s]]);export{m as __pageData,p as default};
